INSERT IGNORE INTO `pertanyaan_proteksi` (`id`, `sub_kategori_id`, `ruang_lingkup_id`, `pertanyaan_proteksi`, `index0`, `index1`, `index2`, `index3`, `index4`, `index5`, `created_at`, `updated_at`) VALUES
(1, 26, 4, 'Menetapkan dan menerapkan prosedur untuk menerbitkan, mengelola, memeriksa, membatalkan, dan memantau informasi tentang identitas dan kredensial terhadap aset informasi dan personel yang menggunakan Sistem Elektronik. ', 'Belum memiliki prosedur pengelolaan aset informasi dan personel yang menggunakan Sistem Elektronik', 'Prosedur pengelolaan aset informasi dan personel yang menggunakan Sistem Elektronik sudah diterapkan pada sebagian kecil aspek namun belum diformalkan', 'Prosedur pengelolaan aset informasi dan personel yang menggunakan Sistem Elektronik sudah diterapkan pada sebagian besar aspek namun belum diformalkan', 'Prosedur pengelolaan aset informasi dan personel yang menggunakan Sistem Elektronik sudah diformalkan dan diterapkan pada seluruh aspek', '- Prosedur pengelolaan aset informasi dan personel yang menggunakan Sistem Elektronik sudah diformalkan dan diterapkan pada seluruh aspek.\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala.', '- Prosedur pengelolaan aset informasi dan personel yang menggunakan Sistem Elektronik sudah diformalkan dan diterapkan pada seluruh aspek.\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala, serta dilakukan perbaikan secara berkelanjutan.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(2, 27, 4, 'Penyelenggara Sistem Elektronik menyusun prosedur tentang mekanisme identifikasi pengguna layanan, pemberian akses, dan otorisasi terhadap layanan, termasuk pemberian koneksi terhadap pengguna, perangkat IoT, dan/atau server.', 'Belum memiliki prosedur mekanisme identifikasi pengguna layanan, pemberian akses, dan otorisasi terhadap layanan', 'Prosedur mekanisme identifikasi pengguna layanan, pemberian akses, dan otorisasi terhadap layanan sudah diterapkan pada sebagian kecil aspek namun belum diformalkan', 'Prosedur mekanisme identifikasi pengguna layanan, pemberian akses, dan otorisasi terhadap layanan sudah diterapkan pada sebagian besar aspek namun belum diformalkan', 'Prosedur mekanisme identifikasi pengguna layanan, pemberian akses, dan otorisasi terhadap layanan sudah diformalkan dan diterapkan pada seluruh aspek', '- Prosedur mekanisme identifikasi pengguna layanan, pemberian akses, dan otorisasi terhadap layanan sudah diformalkan dan diterapkan pada seluruh aspek.\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala.', '- Prosedur mekanisme identifikasi pengguna layanan, pemberian akses, dan otorisasi terhadap layanan sudah diformalkan dan diterapkan pada seluruh aspek.\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala, serta dilakukan perbaikan secara berkelanjutan.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(3, 27, 2, 'Tersedianya dan diterapkannya prosedur pencegahan terhadap upaya memasuki perangkat atau jaringan secara tidak sah, dengan menerapkan langkah-langkah seperti menerapkan fungsi untuk penguncian setelah sejumlah upaya masuk yang gagal dan memberikan interval waktu hingga keamanannya dipastikan.', 'Belum memiliki prosedur pencegahan terhadap upaya serangan melalui perangkat atau jaringan', 'Prosedur pencegahan terhadap upaya serangan melalui perangkat atau jaringan sudah diterapkan pada sebagian kecil aspek namun belum diformalkan ', 'Prosedur pencegahan terhadap upaya serangan melalui perangkat atau jaringan sudah diterapkan pada sebagian besar aspek namun belum diformalkan ', 'Prosedur pencegahan terhadap upaya serangan melalui perangkat atau jaringan sudah diformalkan dan diterapkan pada seluruh aspek', '- Prosedur pencegahan terhadap upaya serangan melalui perangkat atau jaringan sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala', '- Prosedur pencegahan terhadap upaya serangan melalui perangkat atau jaringan sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala, serta dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(4, 28, 4, 'Menyusun dan menerapkan prosedur untuk memisahkan hak akses sesuai tugas dan area tanggung jawab (misalnya, pisahkan fungsi untuk pengguna dari fungsi untuk administrator sistem)', 'Belum memiliki prosedur pemisahan hak akses', 'Prosedur pemisahan hak akses sudah diterapkan pada sebagian kecil aspek namun belum diformalkan', 'Prosedur pemisahan hak akses sudah diterapkan pada sebagian besar aspek namun belum diformalkan', 'Prosedur pemisahan hak akses sudah diformalkan dan diterapkan pada seluruh aspek', '- Prosedur pemisahan hak akses sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala', '- Prosedur pemisahan hak akses sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala, serta dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(5, 28, 2, 'Tersedianya prosedur pembatasan komunikasi oleh perangkat dan server kepada pengguna sesuai dengan tingkat risikonya.', 'Belum memiliki prosedur pembatasan komunikasi perangkat dan server', 'Prosedur pembatasan komunikasi perangkat dan server sudah diterapkan pada sebagian kecil aspek namun belum diformalkan', 'Prosedur pembatasan komunikasi perangkat dan server sudah diterapkan pada sebagian besar aspek namun belum diformalkan', 'Prosedur pembatasan komunikasi perangkat dan server sudah diformalkan diterapkan pada seluruh aspek', '- Prosedur pembatasan komunikasi perangkat dan server sudah diformalkan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala', '- Prosedur pembatasan komunikasi perangkat dan server sudah diformalkan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala, serta dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(6, 29, 4, 'Perangkat, pengguna, dan aset informasi lainnya menggunakan sistem otentikasi tertentu (misalnya, multi-factor authentication) sesuai dengan tingkat risiko nya terhadap sistem.', 'Belum memiliki sistem otentikasi untuk perangkat, pengguna, dan aset informasi lainnya', 'Sistem otentikasi untuk perangkat, pengguna, dan aset informasi lainnya sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', 'Sistem otentikasi untuk perangkat, pengguna, dan aset informasi lainnya sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', 'Sistem otentikasi untuk perangkat, pengguna, dan aset informasi lainnya sudah diformalkan dan diterapkan pada seluruh aspek', '- Sistem otentikasi untuk perangkat, pengguna, dan aset informasi lainnya sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Sistem tersebut dimonitor pelaksanaanya dan direview secara berkala', '- Sistem otentikasi untuk perangkat, pengguna, dan aset informasi lainnya sudah diformalkan dan diterapkan pada seluruh aspek, serta dilakukan otomatisasi\r\n- Sistem tersebut dimonitor pelaksanaanya dan direview secara berkala', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(7, 30, 4, 'Menetapkan dan menerapkan prosedur keamanan fisik terhadap akses kontrol yang sesuai seperti mengunci dan membatasi akses ke area tempat perangkat dan server dipasang, menggunakan kontrol masuk dan keluar, otentikasi biometrik, memasang kamera pengintai, dan/atau memeriksa barang bawaan.', 'Belum memiliki prosedur keamanan fisik terhadap akses kontrol ', 'Prosedur keamanan fisik terhadap akses kontrol sudah diterapkan pada sebagian kecil aspek namun belum diformalkan', 'Prosedur keamanan fisik terhadap akses kontrol sudah diterapkan pada sebagian besar aspek namun belum diformalkan', 'Prosedur keamanan fisik terhadap akses kontrol sudah diformalkan dan diterapkan pada seluruh aspek', '- Prosedur keamanan fisik terhadap akses kontrol sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala', '- Prosedur keamanan fisik terhadap akses kontrol sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala, serta dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(8, 30, 1, 'Tersedianya dan diterapkannya prosedur pelindungan fisik seperti menyiapkan catu daya cadangan, fasilitas proteksi kebakaran, dan perlindungan dari resapan air yang mengikuti kebijakan dan standar yang berlaku.', 'Belum memiliki prosedur pelindungan aset fisik ', 'Prosedur pelindungan aset fisik sudah diterapkan pada sebagian kecil aspek namun belum diformalkan', 'Prosedur pelindungan aset fisik sudah diterapkan pada sebagian besar aspek namun belum diformalkan', 'Prosedur pelindungan aset fisik sudah diformalkan dan diterapkan pada seluruh aspek', '- Prosedur pelindungan aset fisik sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala', '- Prosedur pelindungan aset fisik sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala, serta dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(9, 30, 4, 'Tersedianya prosedur dan sarana pengamanan terhadap perangkat komputer yang digunakan untuk pengolahan data Sistem Elektronik.', 'Belum memiliki prosedur dan sarana pengamanan terhadap perangkat komputer untuk pengolahan data Sistem Elektronik', 'Prosedur pengamanan terhadap perangkat komputer untuk pengolahan data Sistem Elektronik sudah diterapkan pada sebagian kecil aspek beserta sarana pengamanannya namun belum diformalkan', 'Prosedur pengamanan terhadap perangkat komputer untuk pengolahan data Sistem Elektronik sudah diterapkan pada sebagian besar aspek beserta sarana pengamanannya namun belum diformalkan', 'Prosedur pengamanan terhadap perangkat komputer untuk pengolahan data Sistem Elektronik sudah diformalkan dan diterapkan pada seluruh aspek beserta sarana pengamanannya', '- Prosedur pengamanan terhadap perangkat komputer untuk pengolahan data Sistem Elektronik sudah diformalkan dan diterapkan pada seluruh aspek beserta sarana pengamanannya\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala', '- Prosedur pengamanan terhadap perangkat komputer untuk pengolahan data Sistem Elektronik sudah diformalkan dan diterapkan pada seluruh aspek beserta sarana pengamanannya\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala serta dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(10, 31, 4, 'Tentukan metode untuk melakukan pembaruan keamanan dan sejenisnya pada perangkat dan server. Kemudian, terapkan pembaruan keamanan tersebut dengan teknologi yang benar dan tepat pada waktunya.', 'Belum memiliki prosedur pembaruan keamanan dan sejenisnya pada perangkat dan server ', 'Prosedur pembaruan keamanan dan sejenisnya pada perangkat dan server sudah diterapkan pada sebagian kecil aspek namun belum diformalkan', 'Prosedur pembaruan keamanan dan sejenisnya pada perangkat dan server sudah diterapkan pada sebagian besar aspek namun belum diformalkan', 'Prosedur pembaruan keamanan dan sejenisnya pada perangkat dan server sudah diformalkan dan diterapkan pada seluruh aspek', '- Prosedur pembaruan keamanan dan sejenisnya pada perangkat dan server sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala', '- Prosedur pembaruan keamanan dan sejenisnya pada perangkat dan server sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala serta dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(11, 31, 1, 'Dokumentasikan kegiatan pembaruan keamanan pada perangkat organisasi dan laporkan kepada manajemen secara berkala.', 'Kegiatan pembaruan keamanan pada perangkat organisasi belum didokumentasikan dan dilaporkan kepada manajemen secara berkala', 'Kegiatan pembaruan keamanan pada perangkat organisasi sebagian kecil sudah didokumentasikan dan dilaporkan kepada manajemen secara berkala secara informal', 'Kegiatan pembaruan keamanan pada perangkat organisasi sebagian besar sudah didokumentasikan dan dilaporkan kepada manajemen secara berkala secara informal', 'Kegiatan pembaruan keamanan pada perangkat organisasi sudah didokumentasikan seluruhnya dan dilaporkan kepada manajemen secara berkala secara formal', '- Kegiatan pembaruan keamanan pada perangkat organisasi sudah didokumentasikan seluruhnya dan dilaporkan kepada manajemen secara berkala secara formal\r\n- Prosedur dokumentasi dimonitor pelaksanaanya dan direview secara berkala', '- Kegiatan pembaruan keamanan pada perangkat organisasi sudah didokumentasikan seluruhnya dan dilaporkan kepada manajemen secara berkala secara formal\r\n- Prosedur dokumentasi dimonitor pelaksanaanya dan direview secara berkala, serta dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(12, 32, 2, 'Mengidentifikasi perangkat yang memiliki mekanisme pembaruan jarak jauh untuk melakukan pembaruan massal berbagai program perangkat lunak (OS, driver, dan aplikasi) melalui perintah jarak jauh.', 'Belum dilakukan identifikasi perangkat yang memiliki mekanisme pembaruan melalui perintah jarak jauh', 'Identifikasi perangkat yang memiliki mekanisme pembaruan melalui perintah jarak jauh sebagian kecil sudah diidentifikasi secara informal', 'Identifikasi perangkat yang memiliki mekanisme pembaruan melalui perintah jarak jauh sebagian besar sudah diidentifikasi secara informal', 'Identifikasi perangkat yang memiliki mekanisme pembaruan melalui perintah jarak jauh sudah diidentifikasi seluruhnya secara formal', '- Identifikasi perangkat yang memiliki mekanisme pembaruan melalui perintah jarak jauh sudah diidentifikasi seluruhnya secara formal\r\n- Proses identifikasi perangkat dimonitor pelaksanaanya dan direview secara berkala', '- Identifikasi perangkat yang memiliki mekanisme pembaruan melalui perintah jarak jauh sudah diidentifikasi seluruhnya secara formal, serta dilakukan otomatisasi\r\n- Proses identifikasi perangkat dimonitor pelaksanaanya dan direview secara berkala', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(13, 32, 2, 'Melakukan pemeliharaan perangkat dan server yang telah disetujui dari jarak jauh dan mencatat setiap log masuknya, sehingga akses yang tidak sah dapat dicegah.', 'Pemeliharaan perangkat dan server yang disetujui dari jarak jauh belum dilakukan', 'Sebagian kecil perangkat dan server yang disetujui dari jarak jauh sudah dilakukan pemeliharaan namun belum diformalkan', 'Sebagian besar perangkat dan server yang disetujui dari jarak jauh sudah dilakukan pemeliharaan namun belum diformalkan', 'Seluruh perangkat dan server yang disetujui dari jarak jauh sudah dilakukan pemeliharaan dan sudah diformalkan', '- Seluruh perangkat dan server yang disetujui dari jarak jauh sudah dilakukan pemeliharaan dan sudah diformalkan\r\n- Prosedur pemeliharaan perangkat dimonitor pelaksanaanya dan direview secara berkala', '- Seluruh perangkat dan server yang disetujui dari jarak jauh sudah dilakukan pemeliharaan dan sudah diformalkan, dan dilakukan otomatisasi\r\n- Prosedur pemeliharaan perangkat dimonitor pelaksanaanya dan direview secara berkala', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(14, 33, 2, 'Penyelenggara Sistem Elektronik memastikan lingkungan fisik aset Sistem Elektronik dipantau secara tepat melalui pengaturan, perekaman, dan pemantauan akses fisik terhadap aset Sistem Elektronik. (misalnya cctv, akses kontrol, sensor, dll). ', 'Organisasi belum memiliki prosedur pemantauan lingkungan fisik aset Sistem Elektronik ', 'Prosedur pemantauan lingkungan fisik aset Sistem Elektronik sudah diterapkan pada sebagian kecil aspek namun belum diformalkan', 'Prosedur pemantauan lingkungan fisik aset Sistem Elektronik sudah diterapkan pada sebagian besar aspek namun belum diformalkan', 'Prosedur pemantauan lingkungan fisik aset Sistem Elektronik sudah diformalkan dan diterapkan pada seluruh aspek', '- Prosedur pemantauan lingkungan fisik aset Sistem Elektronik sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala', '- Prosedur pemantauan lingkungan fisik aset Sistem Elektronik sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala serta dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(15, 34, 1, 'Penyelenggara Sistem Elektronik senantiasa melakukan peninjauan, analisis, dan peningkatan terhadap kontrol keamanan yang diterapkan sesuai hasil reviu dari respons insiden keamanan dan hasil pemantauan, pengukuran, dan evaluasi ancaman internal dan eksternal. ', 'Organisasi belum memiliki prosedur peninjauan, analisis dan peningkatan terhadap kontrol keamanan yang diterapkan sesuai hasil reviu', 'Prosedur peninjauan, analisis dan peningkatan terhadap kontrol keamanan yang diterapkan sesuai hasil reviu sudah diterapkan pada sebagian kecil aspek namun belum diformalkan', 'Prosedur peninjauan, analisis dan peningkatan terhadap kontrol keamanan yang diterapkan sesuai hasil reviu sudah diterapkan pada sebagian besar aspek namun belum diformalkan', 'Prosedur peninjauan, analisis dan peningkatan terhadap kontrol keamanan yang diterapkan sesuai hasil reviu sudah diformalkan dan diterapkan pada seluruh aspek', '- Prosedur peninjauan, analisis dan peningkatan terhadap kontrol keamanan yang diterapkan sesuai hasil reviu sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala', '- Prosedur peninjauan, analisis dan peningkatan terhadap kontrol keamanan yang diterapkan sesuai hasil reviu sudah diformalkan dan diterapkan pada seluruh aspek\r\n- Prosedur tersebut dimonitor pelaksanaanya dan direview secara berkala serta dilakukan perbaikan secara berkelanjutan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(16, 35, 1, 'Jika Penyelenggara Sistem Elektronik bertukar informasi yang perlu dilindungi dengan organisasi lain, maka Penyelenggara Sistem Elektronik perlu meminta organisasi lain tersebut untuk menyetujui persyaratan keamanan untuk pelindungan informasi tersebut.', '- Organisasi belum meminta organisasi lain untuk menyetujui persyaratan keamanan untuk perlindungan informasi yang ditukarkan. \r\n- Organisasi belum memiliki kebijakan internal atau prosedur teknis mengenai pertukaran informasi yang perlu dilindungi dengan organisasi lain.\r\n- Organisasi belum memiliki konsep atau format dokumen persetujuan persyaratan keamanan yang disahkan pimpinan untuk melindungi informasi yang ditukarkan dengan organisasi lain. ', '- Organisasi sudah meminta organisasi lain untuk menyetujui sebagian kecil aspek persyaratan keamanan untuk perlindungan informasi yang ditukarkan. \r\n- Organisasi telah memiliki konsep atau rancangan kebijakan internal atau prosedur teknis mengenai pertukaran informasi yang perlu dilindungi dengan organisasi lain. \r\n-  Organisasi telah memiliki konsep atau format dokumen persetujuan persyaratan keamanan yang  belum disahkan pimpinan untuk melindungi informasi yang ditukarkan dengan organisasi lain.', '- Organisasi sudah meminta organisasi lain untuk menyetujui sebagian besar aspek persyaratan keamanan untuk perlindungan informasi yang ditukarkan. \r\n- Organisasi telah memiliki konsep atau rancangan kebijakan internal atau prosedur teknis mengenai pertukaran informasi yang perlu dilindungi dengan organisasi lain. \r\n-  Organisasi telah memiliki konsep atau format dokumen persetujuan persyaratan keamanan yang belum disahkan pimpinan untuk melindungi informasi yang ditukarkan dengan organisasi lain.', '- Organisasi sudah meminta organisasi lain untuk menyetujui seluruh aspek persyaratan keamanan untuk perlindungan informasi yang ditukarkan. \r\n- Organisasi telah memiliki kebijakan internal atau prosedur teknis yang diformalkan mengenai pertukaran informasi yang perlu dilindungi dengan organisasi lain. \r\n-  Organisasi telah memiliki format dokumen persetujuan persyaratan keamanan yang disahkan pimpinan untuk melindungi informasi yang ditukarkan dengan organisasi lain.', '- Organisasi sudah meminta organisasi lain untuk menyetujui seluruh aspek persyaratan keamanan untuk perlindungan informasi yang ditukarkan. \r\n- Organisasi telah memiliki kebijakan internal atau prosedur teknis yang diformalkan, dimonitoring, dan direview secara berkala mengenai pertukaran informasi yang perlu dilindungi dengan organisasi lain. \r\n-  Organisasi telah memiliki format dokumen persetujuan persyaratan keamanan yang disahkan pimpinan, dimonitoring, dan direview secara berkala untuk melindungi informasi yang ditukarkan dengan organisasi lain.', '- Organisasi sudah meminta organisasi lain untuk menyetujui seluruh aspek persyaratan keamanan untuk perlindungan informasi yang ditukarkan. \r\n- Organisasi telah memiliki kebijakan internal atau prosedur teknis yang diformalkan, dimonitoring, direview secara berkala dan dilakukan perbaikan mengenai pertukaran informasi yang perlu dilindungi dengan organisasi lain. \r\n-  Organisasi telah memiliki format dokumen persetujuan persyaratan keamanan yang disahkan pimpinan, dimonitoring, direview dan dilakukan perbaikansecara berkala untuk melindungi informasi yang ditukarkan dengan organisasi lain.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(17, 35, 2, 'Mengenkripsi informasi dengan tingkat kekuatan keamanan yang sesuai standar keamanan.', '- Organisasi belum memiliki kebijakan internal maupun prosedur enkripsi informasi dengan tingkat kekuatan keamanan sesuai dengan standar keamanan;\r\n- Organisasi belum menerapkan enkripsi pada informasi dengan tingkat kekuatan keamanan yang sesuai standar keamanan', '- Organisasi sudah memiliki konsep kebijakan internal maupun prosedur enkripsi informasi dengan tingkat kekuatan keamanan sesuai dengan standar keamanan\r\n- Organisasi sudah menerapkan enkripsi pada sebagian kecil informasi dengan tingkat kekuatan keamanan yang sesuai standar keamanan', '- Organisasi sudah memiliki konsep kebijakan internal maupun prosedur enkripsi informasi dengan tingkat kekuatan keamanan sesuai dengan standar keamanan\r\n- Organisasi sudah menerapkan enkripsi pada sebagian besar informasi dengan tingkat kekuatan keamanan yang sesuai standar keamanan', '- Organisasi sudah memiliki kebijakan internal maupun prosedur enkripsi informasi yang disahkan pimpinan dengan tingkat kekuatan keamanan sesuai dengan standar keamanan\r\n- Organisasi sudah menerapkan enkripsi pada seluruh informasi dengan tingkat kekuatan keamanan yang sesuai standar keamanan', '- Organisasi sudah memiliki kebijakan internal maupun prosedur enkripsi informasi yang disahkan pimpinan, dimonitoring, dan direview secara berkala dengan tingkat kekuatan keamanan sesuai dengan standar keamanan\r\n- Organisasi sudah menerapkan enkripsi pada seluruh informasi dengan tingkat kekuatan keamanan yang sesuai standar keamanan, dimonitoring penerapannya, dan direview secara berkala\r\n', '- Organisasi sudah memiliki kebijakan internal maupun prosedur enkripsi informasi yang disahkan pimpinan, dimonitoring, direview secara berkala, dan dilakukan perbaikan sesuai dengan standar keamanan\r\n- Organisasi sudah menerapkan enkripsi pada seluruh informasi dengan tingkat kekuatan keamanan yang sesuai standar keamanan, dimonitoring penerap